var fs = global.get('fs') || require('fs');
var path = '/opt/d3kos/config/cloud-credentials.json';
try {
  if (!fs.existsSync(path)) { msg.skip = true; return msg; }
  msg.credentials = JSON.parse(fs.readFileSync(path, 'utf8'));
  msg.skip = false;
} catch(e) {
  msg.skip = true;
}
return msg;

var fs = global.get('fs') || require('fs');
var sk = msg.payload || {};
var nav = (sk.navigation) || {};
var env = (sk.environment) || {};
var prop = (sk.propulsion && sk.propulsion.main) || {};

var firmware = 'unknown';
try { firmware = fs.readFileSync('/opt/d3kos/config/version.txt','utf8').trim(); } catch(e){}

var getValue = function(obj, key) {
  try { return obj[key] && obj[key].value !== undefined ? obj[key].value : null; } catch(e){ return null; }
};

msg.credentials = msg.credentials || {};
msg.payload = {
  device_api_key: msg.credentials.device_api_key,
  boat_uuid: msg.credentials.boat_uuid,
  timestamp: new Date().toISOString(),
  readings: {
    rpm: getValue(prop, 'revolutions'),
    coolant_temp_c: getValue(prop, 'coolantTemperature'),
    fuel_level: getValue(env, 'fuel.level'),
    battery_volts: getValue(env, 'electrical.batteries.house.voltage'),
    gps_lat: getValue(nav, 'position') ? getValue(nav,'position').latitude : null,
    gps_lon: getValue(nav, 'position') ? getValue(nav,'position').longitude : null,
    speed_knots: getValue(nav, 'speedOverGround'),
    heading_deg: getValue(nav, 'headingTrue'),
    firmware_version: firmware
  }
};
msg.headers = {
  'Content-Type': 'application/json',
  'Authorization': 'Bearer ' + msg.credentials.device_api_key
};
return msg;

var fs = global.get('fs') || require('fs');
try {
  fs.writeFileSync('/opt/d3kos/data/telemetry-last-push.txt', new Date().toISOString());
} catch(e){}
return msg;

// Log failed push for retry — write to buffer file
var fs = global.get('fs') || require('fs');
try {
  var entry = JSON.stringify({timestamp: new Date().toISOString(), payload: msg.payload}) + '\n';
  fs.appendFileSync('/opt/d3kos/data/telemetry-buffer.jsonl', entry);
} catch(e){}
return null;
